import React, { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
function Layout() {
  const [open, setOpen] = useState(true);
  const location = useLocation();
  return (
    <div style={{display:'flex',minHeight:'100vh',background:'#0A0F1A'}}>
      <div style={{width:open?'240px':'0px',background:'#1A2332',borderRight:'1px solid #2A3A4A',transition:'width 0.3s',overflow:'hidden',position:'fixed',height:'100vh',top:0,left:0,zIndex:1000}}>
        <div style={{padding:'20px'}}><h1 style={{color:'#3B82F6'}}> CyberSec</h1>
        <nav style={{marginTop:'30px'}}>
          <Link to="/blockchain" style={{display:'flex',padding:'12px 16px',marginBottom:'8px',borderRadius:'8px',textDecoration:'none',color:location.pathname==='/blockchain'?'#3B82F6':'#94A3B8',background:location.pathname==='/blockchain'?'rgba(59,130,246,0.1)':'transparent'}}> Blockchain</Link>
          <Link to="/web3" style={{display:'flex',padding:'12px 16px',marginBottom:'8px',borderRadius:'8px',textDecoration:'none',color:location.pathname==='/web3'?'#3B82F6':'#94A3B8',background:location.pathname==='/web3'?'rgba(59,130,246,0.1)':'transparent'}}> Web3</Link>
        </nav></div>
      </div>
      <div style={{marginLeft:open?'240px':'0px',flex:1,padding:'20px'}}>
        <header style={{display:'flex',justifyContent:'space-between',padding:'16px 24px',background:'#1A2332',borderRadius:'12px',marginBottom:'24px',border:'1px solid #2A3A4A'}}>
          <button onClick={()=>setOpen(!open)} style={{background:'transparent',border:'none',color:'#94A3B8',fontSize:'24px',cursor:'pointer'}}></button>
          <span style={{color:'#3B82F6'}}>Admin</span>
        </header>
        <main><Outlet /></main>
      </div>
    </div>
  );
}
export default Layout;
